```ts
import "dotenv/config";
import { CELL_RE, expandCellSpec } from "../lib/warehouse/codes";

function assert(cond: unknown, msg: string): asserts cond {
  if (!cond) { console.error(`FAIL: ${msg}`); process.exit(1); }
}

function expectArray(r: string[] | { error: string }, msg: string): string[] {
  assert(Array.isArray(r), `${msg} — expected array, got error: ${(r as { error: string }).error}`);
  return r as string[];
}

function expectError(r: string[] | { error: string }, expected: string, msg: string): void {
  assert(!Array.isArray(r), `${msg} — expected error, got array`);
  assert((r as { error: string }).error === expected, `${msg} — error text mismatch: got "${(r as { error: string }).error}"`);
}

async function main(): Promise<void> {
  // positive
  const a = expectArray(expandCellSpec("A-1-1"), "single code");
  assert(a.length === 1 && a[0] === "A-1-1", "single code body");
  // ... etc
  console.log("OK: verify-cell-codes");
}

main().catch((e) => { console.error(e); process.exit(1); });
```
Known current behaviour to lock in (read off `lib/warehouse/codes.ts:42-77` post-PR):
- `split("..")` then `.trim().toUpperCase()` per side
- Equal-segment shortcut: if `as[i] === bs[i]` after upper, dim is `[as[i]]`
- Numeric range guard: `hi - lo > 500` → `"Слишком большой диапазон"`
- Cartesian guard: `acc.length > 1000` → `"Слишком много ячеек (макс. 1000)"`
- Non-numeric mismatch: `"Сегмент ${i + 1}: перебор возможен только по числам"` (1-indexed)
Do NOT add the script to `package.json` scripts — sibling `verify-*.ts` files are not registered there (confirmed: `scripts` block only has `dev`/`build`/`lint`/Prisma plumbing).
